#include<bits/stdc++.h>
using namespace std;
struct student{
	char name[15];
	double zong;
};
student a[110];
int n,cnt=0,k;
int main()
{
	scanf("%d%d",&n,&k);
	for(int i=1;i<=n;i++)
	{
		scanf("%s",a[i].name);
		scanf("%lf",&(a[i].zong));
	}
	for(int i=n;i>=1;i--)
	{
		for(int j=1;j<=i;j++)
		{
			if(a[j].zong<a[j+1].zong)
			{
				swap(a[j],a[j+1]);
			}
		}
	}
	printf("%s %g",a[k].name,a[k].zong);
	return 0;
}
